import { addZeroToNumber as addZero } from '../../Various/addZeroToNumber';
import { removeArgAndAnastDays } from '../../Various/addAndRemoveDays';
import { returnDatesBetween } from '../../Various/returnDatesBetween';

export function anastoliDimosiouFunc(year?: number) {
  const arr = [];
  if (year) {
    for (let i = year - 4; i <= year + 5; i++) {
      for (let k = 1; k <= 31; k++) {
        arr.push(`${i}-07-${addZero(k)}`);
      }
      for (let j = 1; j <= 15; j++) {
        arr.push(`${i}-09-${addZero(j)}`);
      }
    }
  } else {
    for (let i = 0; i < 20; i++) {
      for (let k = 1; k <= 31; k++) {
        arr.push(`20${addZero(i + 15)}-07-${addZero(k)}`);
      }
      for (let j = 1; j <= 15; j++) {
        arr.push(`20${addZero(i + 15)}-09-${addZero(j)}`);
      }
    }
  }
  return removeArgAndAnastDays(arr.flat().sort(), [
    ...returnDatesBetween('2020-07-01', '2020-07-15'),
    ...returnDatesBetween('2020-09-01', '2020-09-15'),
    ...returnDatesBetween('2021-09-01', '2021-09-15'),
  ]);
}

import { getDate } from '../../../CalculateDates/calculateDate';
import { argiesFunc } from '../../../ArgiesAndAnastoli/ArgiesFunc';
import { addArgAndAnastDays } from '../../../Various/addAndRemoveDays';
import { anastoliFunc } from '../../../ArgiesAndAnastoli/AnastoliFunc';
import { extraArgies } from '../../../ArgiesAndAnastoli/extraArgies';

// interface Options {
//   dimosio?: boolean;
// }
export const getOloklirosi = (start: string): string => {
  let argiesDimosiou: string[] = [];
  const days = 40;

  const year = parseInt(start.slice(0, 4));
  let oloklirosi = getDate(start, days, {
    argies: addArgAndAnastDays(argiesFunc(year), [...extraArgies]),
    anastoli: addArgAndAnastDays(anastoliFunc(year), [...argiesDimosiou]),
  });

  return oloklirosi.toISOString().split('T')[0];
};

import { analyseArgies } from '../../../CalculateDates/calculateDate';
import { argiesFunc } from '../../../ArgiesAndAnastoli/ArgiesFunc';
import { addArgAndAnastDays } from '../../../Various/addAndRemoveDays';
import { anastoliFunc } from '../../../ArgiesAndAnastoli/AnastoliFunc';
import { extraArgies } from '../../../ArgiesAndAnastoli/extraArgies';
import { reverseDate } from '../../../Various/reverseDate';

export const getOloklirosiAddedDays = (start: string) => {
  let text: {
    nomothesia: string[];
    ypologismos: string[];
    imeres: string[];
  } = { nomothesia: [], ypologismos: [], imeres: [] };

  text.imeres.push(
    '40 ημέρες από την επομένη της λήξης της προθεσμίας για την υποχρεωτική αρχική συνεδρία διαμεσολάβησης.'
  );

  let argiesDimosiou: string[] = [];
  let days = 40;

  const year = parseInt(start.slice(0, 4));

  const argia = analyseArgies(start, days, {
    argies: addArgAndAnastDays(argiesFunc(year), [...extraArgies]),
    anastoli: addArgAndAnastDays(anastoliFunc(year), [...argiesDimosiou]),
  });
  let dayOfWeek = '';
  if (new Date(argia).getDay() === 0) {
    dayOfWeek = ' (Κυριακή)';
  }
  if (new Date(argia).getDay() === 6) {
    dayOfWeek = ' (Σάββατο)';
  }
  if (argia) {
    text.ypologismos.push(
      `Επειδή η ${reverseDate(
        argia
      )} είναι αργία${dayOfWeek}, η ημερομήνια μετατέθηκε στην επομένη εργάσιμη.`
    );
  }

  return text;
};

import { checkIfAnastoliDiakopon } from '../../../Various/checkEarlierOrLaterDate';
import { getOloklirosiAddedDays } from './getOloklirosiAddedDays';

export const getOloklirosiDetails = (start: string, prothesmia: string) => {
  let text: {
    nomothesia: string[];
    ypologismos: string[];
    imeres: string[];
  } = { nomothesia: [], ypologismos: [], imeres: [] };
  text.nomothesia = [
    `Άρθρο 7 παρ. 7 του Ν. 4640/2019: Εφόσον τα μέρη αποφασίσουν να συνεχίσουν τη διαδικασία της διαμεσολάβησης είτε με τον ίδιο είτε με διαφορετικό διαμεσολαβητή, συντάσσεται έγγραφο συμφωνίας υπαγωγής της διαφοράς στη διαδικασία της διαμεσολάβησης και ακολουθείται η διαδικασία του άρθρου 5 του παρόντος, η οποία θα πρέπει να έχει ολοκληρωθεί εντός σαράντα (40) ημερών, που υπολογίζονται από την επομένη της λήξης της ανωτέρω εικοσαήμερης ή τριακονθήμερης προθεσμίας. Τα μέρη δύνανται να συμφωνούν παράταση της προθεσμίας των σαράντα (40) ημερών.\nΤο χρονικό διάστημα από 1 έως 31 Αυγούστου δεν υπολογίζεται στις παραπάνω προθεσμίες.`,
  ];

  if (checkIfAnastoliDiakopon(start, prothesmia)) {
    text.ypologismos.push(
      'Εξαιρέθηκε από τον υπολογισμό το διάστημα από 1η έως 31η Αυγούστου.'
    );
  }
  const addedDaysText = getOloklirosiAddedDays(start);
  text.ypologismos = [...text.ypologismos, ...addedDaysText.ypologismos];
  text.imeres = addedDaysText.imeres;

  return text;
};

