import { Options } from '../../Types/interfaces';
import { checkIfAnastoliDiakopon } from '../../../Various/checkEarlierOrLaterDate';
import { getSynedriaAddedDays } from './getSynedriaAddedDays';

export const getSynedriaDetails = (
  start: string,
  prothesmia: string,
  options?: Options
) => {
  let text: {
    nomothesia: string[];
    ypologismos: string[];
    imeres: string[];
  } = { nomothesia: [], ypologismos: [], imeres: [] };
  text.nomothesia = [
    `Άρθρο 7 παρ. 3 του Ν. 4640/2019: Η υποχρεωτική αρχική συνεδρία διαμεσολάβησης λαμβάνει χώρα το αργότερο εντός είκοσι (20) ημερών από την επομένη της αποστολής στον διαμεσολαβητή του αιτήματος προσφυγής στη διαδικασία διαμεσολάβησης από το επισπεύδον μέρος. Αν κάποιο από τα μέρη διαμένει στο εξωτερικό η ως άνω προθεσμία παρεκτείνεται έως την τριακοστή (30ή) ημέρα από την επομένη της αποστολής του αιτήματος στον διαμεσολαβητή.`,
  ];

  if (checkIfAnastoliDiakopon(start, prothesmia)) {
    text.ypologismos.push(
      'Εξαιρέθηκε από τον υπολογισμό το διάστημα από 1η έως 31η Αυγούστου λόγω δικαστικών διακοπών.'
    );
  }
  const addedDaysText = getSynedriaAddedDays(start, options);
  text.ypologismos = [...text.ypologismos, ...addedDaysText.ypologismos];
  text.imeres = addedDaysText.imeres;

  return text;
};

import { checkValidDate } from '../Various/checkValidDate';
import { getOloklirosi } from './Categories/oloklirosi/getOloklirosi';
import { getOloklirosiDetails } from './Categories/oloklirosi/getOloklirosiDetails';

import { getSynedria } from './Categories/synedria/getSynedria';
import { getSynedriaDetails } from './Categories/synedria/getSynedriaDetails';

import { Options } from './Types/interfaces';

interface ProthesmiesYas {
  synedria: string;
  oloklirosi: string;
  synedriaDetails: {
    nomothesia: string[];
    ypologismos: string[];
    imeres: string[];
  };
  oloklirosiDetails: {
    nomothesia: string[];
    ypologismos: string[];
    imeres: string[];
  };
}

export const prothesmiesYas = (
  gnostopoiisi: string,
  options?: Options
): ProthesmiesYas => {
  if (!checkValidDate(gnostopoiisi)) {
    throw new Error(
      "Πρέπει να εισάγετε έγκυρη ημερομηνία της μορφής 'ΕΕΕΕ-ΜΜ-ΗΗ' (πχ. '2022-04-28')"
    );
  }
  if (gnostopoiisi < '2015-01-01') {
    throw new Error('Επιτρέπονται οι ημερομηνίες από 01.02.2022 και έπειτα.');
  }
  let exoterikou = options?.exoterikou ?? false;

  let optionsDefault: Options = {
    exoterikou,
  };

  let synedria = getSynedria(gnostopoiisi, options ? options : optionsDefault);
  let oloklirosi = getOloklirosi(synedria);

  const prothesmies: ProthesmiesYas = {
    synedria,
    oloklirosi,
    synedriaDetails: getSynedriaDetails(
      gnostopoiisi,
      synedria,
      options ? options : optionsDefault
    ),
    oloklirosiDetails: getOloklirosiDetails(synedria, oloklirosi),
  };

  return prothesmies;
};
